sql:
SELECT goals
FROM top_scorers
WHERE season = '2022-2023';

external_knowledge:
- 'League rank' refers to the team's position in their respective football league; 
- 'Expected goals (xG)' is a metric that measures the quality of a shot based on several factors, including the location on the field and the type of shot; 
- 'Expected goals against (xGA)' measures the quality of shots against a team; 
- 'Goal difference' is the difference between the total goals scored by a team and the total goals scored against them; 
- 'Pass accuracy percentage' measures the percentage of successful passes made by a player or team; 
- 'Top scorer' refers to the player with the most goals for a team in a given season.

sql:
SELECT SUM(goals_in_season) AS total_goals_2022_2023
FROM top_scorers
WHERE season = '2022-2023';

SELECT season, MAX(goals_in_season) AS highest_goals_in_season
FROM top_scorers
GROUP BY season;
